var e=[{id:`L5_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`에? 벌써 끝? 아직 화력의 절반도 못 쏟아부었는데!!`,JPN:`え？　もう終わりですか？　まだ火力の半分も使っていません！！`,ENG:`Eh? That's it? But I didn't even use half my firepower!`,TWN:`嗯？這麼快就結束了？我才用不到一半的火力欸！！`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`WORKER_FRONTBAY_NULL_MONITOR`,text:{KOREA:`어디서 오신 분들인진 모르지만, 저흴 구해주셔서 감사합니다.`,JPN:`どこから来たのかはわかりませんが、助けてくださってありがとうございました。`,ENG:`I don't know where you're from, but thank you for saving us.`,TWN:`雖然不認識你們，但謝謝你們的救命之恩。`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`WORKER_FRONTBAY_NULL_MONITOR`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`WORKER_FRONTBAY_NULL_MONITOR`,text:{KOREA:`이 은혜를 어떻게 갚아야 할지.`,JPN:`この恩はどう返せばいいのか。`,ENG:`We don't know how to repay this.`,TWN:`真不知道該怎麼報答你們才好。`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`WORKER_FRONTBAY_NULL_MONITOR`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`간단해. 크레딧으로 줘.`,JPN:`簡単だ。クレジットをくれ。`,ENG:`Simple. Just give us Credits.`,TWN:`很簡單，給我金幣。`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`WORKER_FRONTBAY_NULL_MONITOR`,face:`UNIT_IDLE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`WORKER_FRONTBAY_NULL_MONITOR`,text:{KOREA:`…예?`,JPN:`……はい？`,ENG:`Pardon...?`,TWN:`…什麼？`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`WORKER_FRONTBAY_NULL_MONITOR`,face:`UNIT_IDLE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`당신의 목숨값을 크레딧으로 보답한다-`,JPN:`あなたの命代、クレジットで払え。`,ENG:`Give us Credits equal to your life's worth.`,TWN:`用金幣報答我們的救命之恩，`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`WORKER_FRONTBAY_NULL_MONITOR`,face:`UNIT_IDLE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`간단한 얘기잖아?`,JPN:`簡単な話だろ？`,ENG:`Simple, isn't it?`,TWN:`很難懂嗎？`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`WORKER_FRONTBAY_NULL_MONITOR`,face:`UNIT_IDLE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L15_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`어서 내놓으시죠! 당신들의 목숨값!`,JPN:`早く出しなさい！　あなたたちの命代！`,ENG:`Hand it over! What you think your life is worth!`,TWN:`快交出來吧！你們的救命錢！`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`WORKER_FRONTBAY_NULL_MONITOR`,text:{KOREA:`그… 그러기엔 지금 그럴 만한 돈이 없는데…`,JPN:`で……でも今手持ちのお金がないのですが……`,ENG:`I... I don't have the money at the moment...`,TWN:`這…這個，我們現在身上沒有錢…`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`WORKER_FRONTBAY_NULL_WATCH`,text:{KOREA:`일꾼 7N-51, 7N-54번! 담당 섹터도 아닌 곳에서 뭐하고 있는 거냐!`,JPN:`人夫7N-51、7N-54番！　担当セクターでもないところで今、何しているんだ！`,ENG:`Worker 7N-51, 7N-54! What are you doing at a different sector?!`,TWN:`工人7N-51號和7N-54號！在幹嘛，那裡又不是你們負責的區域！`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`WORKER_FRONTBAY_NULL_WATCH`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`},{id:`L22_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`아, 이런-`,JPN:`あっちゃー`,ENG:`O-oh, no.`,TWN:`糟…糟糕。`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L23_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`윽…! 걸렸다.`,JPN:`うっ……！　バレました。`,ENG:`Kgh...! We're caught.`,TWN:`呃…！被逮個正著。`},stage:{bg:`SKY`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_SURPRISE`}}}}];export{e as default};